phase1.code:
#include <iostream>
#include <string>

class Enemy {
private:
    std::string name;
    int health;

public:
    Enemy(std::string n, int h) : name(n), health(h) {
        std::cout << "Enemy " << name << " created! (" << this << ")" << std::endl;
    }

    ~Enemy() {
        std::cout << "Enemy " << name << " destroyed! (" << this << ")" << std::endl;
    }

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }
};

int main() {
    std::cout << "=== Dynamic Allocation with new and delete ===" << std::endl;

    // 1. Allocate a single object
    std::cout << "\n--- Allocating a single object ---" << std::endl;
    Enemy* goblin = new Enemy("Goblin", 30);
    goblin->display();
    delete goblin;  // Free memory

    // 2. Allocate an array
    std::cout << "\n--- Allocating an array ---" << std::endl;
    int* numbers = new int[5];
    for (int i = 0; i < 5; i++) {
        numbers[i] = (i + 1) * 10;
        std::cout << "numbers[" << i << "] = " << numbers[i] << std::endl;
    }
    delete[] numbers;  // Free array

    // 3. Allocate an array of objects
    std::cout << "\n--- Allocating an array of objects ---" << std::endl;
    Enemy** enemies = new Enemy*[3];
    enemies[0] = new Enemy("Goblin", 30);
    enemies[1] = new Enemy("Orc", 50);
    enemies[2] = new Enemy("Skeleton", 25);

    for (int i = 0; i < 3; i++) {
        enemies[i]->display();
    }

    // Delete in reverse order
    for (int i = 2; i >= 0; i--) {
        delete enemies[i];
    }
    delete[] enemies;

    std::cout << "\n--- Important Rules ---" << std::endl;
    std::cout << "new → delete" << std::endl;
    std::cout << "new[] → delete[]" << std::endl;
    std::cout << "Never mix them!" << std::endl;

    return 0;
}

