phase3.solution:
#include <iostream>
#include <string>

int main() {
    // 1. Single int
    int* num = new int(42);
    std::cout << "Single int: " << *num << " (address: " << num << ")" << std::endl;
    delete num;

    // 2. Array of ints
    int* arr = new int[5];
    for (int i = 0; i < 5; i++) {
        arr[i] = (i + 1) * 10;
    }
    std::cout << "\nArray values:" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << "arr[" << i << "] = " << arr[i] << std::endl;
    }
    delete[] arr;

    // 3. String
    std::string* str = new std::string("Hello");
    std::cout << "\nString: " << *str << " (address: " << str << ")" << std::endl;
    delete str;

    return 0;
}
